import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { TimeSeriesQuery } from '../../src/models/analytics.js';

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: 'test@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ---------- getOrderMetricSummary ----------

  describe('getOrderMetricSummary', () => {
    it('should return zeroes for empty dataset', () => {
      const result = service.getOrderMetricSummary();
      expect(result.totalOrders).toBe(0);
      expect(result.totalRevenue).toBe(0);
      expect(result.averageOrderValue).toBe(0);
      expect(result.averageItemsPerOrder).toBe(0);
      expect(result.ordersByStatus).toEqual({
        pending: 0,
        confirmed: 0,
        shipped: 0,
        delivered: 0,
        cancelled: 0,
      });
    });

    it('should compute correct metrics for a single order', () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 }],
        total: 30,
        status: 'pending',
      }));

      const result = service.getOrderMetricSummary();
      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(30);
      expect(result.averageOrderValue).toBe(30);
      expect(result.averageItemsPerOrder).toBe(3);
      expect(result.ordersByStatus.pending).toBe(1);
    });

    it('should compute correct metrics for multiple orders', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 50 }] }));
      orderRepo.save(makeOrder({ id: 'o2', total: 50, status: 'confirmed',
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 }] }));
      orderRepo.save(makeOrder({ id: 'o3', total: 150, status: 'pending',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 },
          { productId: 'p3', name: 'Doohickey', quantity: 2, unitPrice: 25 },
        ] }));

      const result = service.getOrderMetricSummary();
      expect(result.totalOrders).toBe(3);
      expect(result.totalRevenue).toBe(300);
